/*
* By Diego Tapia
*/

const currentUser = ProcessMaker.user.id;
let PMQL = this.PMQL
let code = ""
let CQP_CURRENCY = this.CQP_CURRENCY
let CQP_SEARCH = this.CQP_SEARCH 
let START_DATE = this.START_DATE
let END_DATE = this.END_DATE

try {
    $("#recordScreenContainer").css("max-width", "97%");
} catch (error) {}

if (CQP_CURRENCY != undefined && CQP_CURRENCY != null && CQP_CURRENCY != "") {
    window.CQP_CURRENCY = CQP_CURRENCY
}

if (CQP_SEARCH !== undefined) {
    var data = {
        CQP_SEARCH: CQP_SEARCH,
        START_DATE: START_DATE,
        END_DATE: END_DATE,
        currentUserId: currentUser,
        currency: window.CQP_CURRENCY
    };

    var jsonData = JSON.stringify(data);
    var encodedData = encodeURIComponent(jsonData);

    var screenHeight = 768;
    if (typeof top.innerHeight != 'undefined') {
        screenHeight = top.innerHeight - 310;
    }
    code = `<body style="margin:0px;padding:0px;overflow:hidden;width:` + screenHeight + `px">
        <iframe id='bulkIframe' src="/api/1.0/pstools/script/cqp_BDRX_report?data=` + encodedData + `" frameborder="0" 
                style="overflow:hidden;overflow-x:hidden;overflow-y:hidden;height:` + screenHeight + `px;width:100%;top:110px;left:0px;right:0px;bottom:0px" 
        ></iframe>
    </body>`;
}

return code;

/*
* By Diego Tapia
*/

let file = this.content

if (file != null && file != undefined && file != "") {
    file = file.fileContents

    if (file != null && file != "" && file != undefined ) {
        const dateObj = new Date();
        var a = document.createElement("a"); 
        a.href = "data:application/vnd.openxmlformats-officedocument.spreadsheetml.sheet;base64," + file; 
        a.download = "BDRX-report_" + (dateObj.getUTCMonth() + 1) + "_" + dateObj.getUTCDate() + "_" + dateObj.getUTCFullYear() + ".xlsx";
        a.click(); 
        window.generated = false
    }

    window.generated = false
}

/*
* By Diego Tapia
*/

let EXPORT_REPORT = this.EXPORT_REPORT
let parameters = {}
const iframeElement = document.getElementById('bulkIframe')

if (iframeElement != null && iframeElement != undefined && iframeElement != "") {
    parameters.query = iframeElement.contentWindow.sqlQuery
    parameters.columns = JSON.parse(JSON.stringify(iframeElement.contentWindow.responseFormat))
    parameters.columns.splice(0, 1);
    parameters.columns.splice(0, 1);
    parameters.columns.splice(72, 1);
    parameters.columns.splice(72, 1);
    return escape(JSON.stringify(parameters));
}

let CQP_CANCEL = this.CQP_CANCEL
let CQP_UPDATE = this.CQP_COMPLETE_UPDATE

// Check if a row has been updated to refresh the data table
if (CQP_UPDATE != null && CQP_UPDATE != undefined  && CQP_UPDATE != "") {
    if (window.updateCode != CQP_UPDATE.updatedId) {
        window.updateCode = CQP_UPDATE.updatedId
        var iframe = document.getElementById('bulkIframe');
        iframe.contentWindow.postMessage({ "update": true }); 
    }
}

let button = $(".show .modal-dialog .modal-content .modal-footer .btn-primary")

// Close modal
if (button != null && button != undefined  && button != "") {
    $(".show .modal-dialog .modal-content .modal-footer .btn-primary").click()
    document.querySelector('[name="CQP_NEW_FX_RATE"]').value = ""
    document.querySelector('[name="CQP_NEW_FX_RATE"]').dispatchEvent(
        new Event("input", {bubbles: true, cancelable:true})
    );
}

return ""

/*
* By Diego Tapia
*/

let CQP_ROW_DATA = this.CQP_ROW_DATA
const iframeElement = document.getElementById('bulkIframe')

if (iframeElement != null && iframeElement != undefined && iframeElement != "") {
    if (iframeElement.contentWindow.row != null && iframeElement.contentWindow.row != undefined && iframeElement.contentWindow.row != "") {
        return iframeElement.contentWindow.row.dataset
    }
}
